    let wd = 1.0 / (1e-6 + abs(get_norm_pixel(xi, yi + 2) - c) + abs(get_norm_pixel(xi, yi + 1) - get_norm_pixel(xi, yi - 1)));
    return (wu * u0 + wd * d0) / max(wu + wd, 1e-6);
